import React from "react";
import { Link } from "react-router-dom";
import TodoList from "../components/TodoList";

function HomePage() {
  return (
    <div>
      <h2>Accueil</h2>
      <p>
        Bienvenue dans Smart Task Hooks, une application React moderne basée sur
        les hooks.
      </p>

      <Link className="link-btn" to="/hooks">
        Voir les hooks
      </Link>

      <Link className="link-btn" to="/about">
        À propos
      </Link>

      <TodoList />
    </div>
  );
}

export default HomePage;
